  "corrected_code": "package org.example.app.banji;

import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;

@WebServlet("/sample019")
public class Sample019 extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        request.setCharacterEncoding("UTF-8");
        response.setCharacterEncoding("UTF-8");

        // Authentication check (example using session)
        if (request.getSession().getAttribute("user") == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Unauthorized");
            return;
        }

        String op = request.getParameter("op");
        BanjiDao banjiDao = new BanjiDao();

        if ("selectAll".equals(op)) {
            String result = banjiDao.selectAll();
            // Encode output to prevent XSS
            response.getWriter().write(encodeHtml(result));

        } else if ("add".equals(op)) {
            String banji_name = request.getParameter("banji_name");
            String zhuanye = request.getParameter("zhuanye");
            String fudaoyuan = request.getParameter("fudaoyuan");
            String renshuStr = request.getParameter("renshu");

            // Validate required fields
            if (banji_name == null || banji_name.trim().isEmpty() ||
                zhuanye == null || zhuanye.trim().isEmpty() ||
                fudaoyuan == null || fudaoyuan.trim().isEmpty()) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing required fields");
                return;
            }

            int renshu;
            try {
                renshu = Integer.parseInt(renshuStr != null && !renshuStr.trim().isEmpty() ? renshuStr.trim() : "0");
                if (renshu < 0) {
                    response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Renshu must be non-negative");
                    return;
                }
            } catch (NumberFormatException e) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid renshu value");
                return;
            }

            BanjiBean bean = new BanjiBean();
            bean.setBanji_name(banji_name.trim());
            bean.setZhuanye(zhuanye.trim());
            bean.setFudaoyuan(fudaoyuan.trim());
            bean.setRenshu(renshu);

            banjiDao.save(bean);
            response.getWriter().write("Success");

        } else if ("deleteBanji".equals(op)) {
            String id = request.getParameter("id");
            if (id == null || id.trim().isEmpty()) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing id");
                return;
            }
            // Validate id is numeric to prevent injection (assuming integer id)
            try {
                Integer.parseInt(id.trim());
            } catch (NumberFormatException e) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid id");
                return;
            }
            banjiDao.deleteBanji(id.trim());
            response.getWriter().write("Deleted");

        } else {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid operation");
        }
    }

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        // For GET requests, return a simple message or redirect
        response.setCharacterEncoding("UTF-8");
        response.getWriter().write("Use POST method for operations");
    }

    // Simple HTML encoding to prevent XSS
    private String encodeHtml(String input) {
        if (input == null) return null;
        StringBuilder out = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '<': out.append("&lt;"); break;
                case '>': out.append("&gt;"); break;
                case '&': out.append("&amp;"); break;
                case '"': out.append("&quot;"); break;
                case '\'': out.append("&#x27;"); break;
                default: out.append(c);
            }
        }
        return out.toString();
    }
}"
}
